/* pipe_ex1.c — producer-consumer with POSIX read/write */
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <ctype.h>
#include <sys/wait.h>

int main() {
    int fds[2];
    pipe(fds);

    if (fork() == 0) {
        /* Child: consumer — reads from pipe */
        close(fds[1]);          /* close write end */
        char c;
        while (read(fds[0], &c, 1) > 0)
            printf("%c", c);
        close(fds[0]);
        exit(0);
    }
    /* Parent: producer — writes to pipe */
    close(fds[0]);              /* close read end */
    char c;
    while (read(0, &c, 1) > 0) {  /* read from stdin */
        if (islower(c))
            write(fds[1], &c, 1);
    }
    close(fds[1]);
    wait(NULL);
    return 0;
}

